<?php require_once __DIR__.'/includes/db.php'; require_login(); page_header(tr('syllabus'),'syllabus'); $q=trim($_GET['q']??''); $where='';$params=[]; if($q!==''){ $where='WHERE discipline_name LIKE ? OR title LIKE ? OR keywords LIKE ?'; $params=['%'.$q.'%','%'.$q.'%','%'.$q.'%']; } $items=table_exists('ai_syllabus_topics')?rows("SELECT * FROM ai_syllabus_topics $where ORDER BY syllabus_topic_id DESC LIMIT 500",$params):[]; ?><div class="card"><div class="toolbar"><h2><?=h(tr('syllabus'))?></h2><form method="get"><input type="hidden" name="lang" value="<?=h(current_lang())?>"><input class="input" name="q" value="<?=h($q)?>" placeholder="<?=h(tr('search_placeholder'))?>"><button class="btn"><?=h(tr('search'))?></button></form></div><div class="table-wrap"><table class="table"><thead><tr><th>ID</th><th><?=h(tr('discipline'))?></th><th><?=h(tr('course'))?></th><th>Код</th><th><?=h(tr('title'))?></th><th>Keywords</th></tr></thead><tbody><?php foreach($items as $r):?><tr><td><?=h($r['syllabus_topic_id'])?></td><td><?=h($r['discipline_name'])?></td><td><?=h($r['course_number'])?></td><td><?=h($r['topic_code'])?></td><td><?=h($r['title'])?></td><td><?=h(mb_substr($r['keywords']??'',0,180))?></td></tr><?php endforeach;?><?php if(!$items):?><tr><td colspan="6" class="empty"><?=h(tr('no_data'))?></td></tr><?php endif;?></tbody></table></div></div><?php page_footer(); ?>